const first = items?.[0]?.json ?? {};
const payload = first.body ?? first;

const sourceTextRaw = (payload.sourceText || payload.text || payload.prompt || '').toString().trim();
if (!sourceTextRaw) {
  throw new Error('Нужно передать sourceText (или text/prompt)');
}

const maxInputChars = Number(payload.maxInputChars || 12000);
const sourceText = sourceTextRaw.length > maxInputChars
  ? `${sourceTextRaw.slice(0, maxInputChars)}\n\n[Текст сокращен для LLM по лимиту ${maxInputChars} символов]`
  : sourceTextRaw;

const projectTitle = (payload.projectTitle || payload.title || 'Без названия').toString().trim();
const model = (payload.model || 'qwen3.6:35b').toString().trim();
const departments = Array.isArray(payload.departments) ? payload.departments : [];

const deptList = departments
  .map((d) => {
    const code = (d?.code || '').toString().trim();
    const name = (d?.name || '').toString().trim();
    const description = (d?.description || '').toString().trim();
    if (!code && !name) return null;
    return `- ${code || 'N/A'} | ${name || 'Без названия'}${description ? ` | ${description}` : ''}`;
  })
  .filter(Boolean)
  .join('\n');

const systemPrompt = [
  'Ты аналитик университета.',
  'Верни только ОДИН валидный JSON-объект. Никакого markdown, комментариев и пояснений.',
  'Не выдумывай факты. Если данных мало — явно укажи это в тексте полей.',
  'Пиши максимально лаконично.',
  'Приоритет строго: high | medium | low.',
  'Ограничения объема:',
  '- summary: до 700 символов',
  '- tasks: максимум 6 элементов',
  '- task.description: до 220 символов',
  '- departmentSuggestions: максимум 4 элемента',
  '- emailBody: до 900 символов',
  'Структура строго такая:',
  '{',
  '  "summary": "...",',
  '  "tasks": [',
  '    { "title": "...", "description": "...", "priority": "high|medium|low" }',
  '  ],',
  '  "departmentSuggestions": [',
  '    {',
  '      "departmentCode": "...",',
  '      "relevanceReason": "...",',
  '      "problemFragment": "...",',
  '      "adaptedPitch": "...",',
  '      "emailSubject": "...",',
  '      "emailBody": "..."',
  '    }',
  '  ]',
  '}'
].join('\n');

const userPrompt = [
  `Название проекта: ${projectTitle}`,
  '',
  'Текст запроса/стенограммы:',
  sourceText,
  '',
  deptList ? `Подразделения:\n${deptList}` : 'Подразделения не переданы.'
].join('\n');

const ollamaRequest = {
  model,
  think: false,
  stream: false,
  format: 'json',
  keep_alive: '30m',
  messages: [
    { role: 'system', content: systemPrompt },
    { role: 'user', content: userPrompt }
  ],
  options: {
    temperature: 0,
    top_p: 0.9,
    num_predict: 2400,
    num_ctx: 8192,
    repeat_penalty: 1.1
  }
};

return [{
  json: {
    projectTitle,
    sourceText,
    departments,
    model,
    ollamaRequest
  }
}];

const rawItem = items?.[0]?.json ?? {};
const rawText = (rawItem?.message?.content || rawItem?.response || '').toString().trim();
const doneReason = (rawItem?.done_reason || '').toString();

if (!rawText) {
  throw new Error('Модель вернула пустой ответ (message.content пустой)');
}

const stripMarkdownFences = (text) => {
  let t = text.trim();
  if (t.startsWith('```')) {
    t = t.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/, '').trim();
  }
  return t;
};

const extractFirstJsonObject = (text) => {
  const s = text;
  let start = -1;
  let depth = 0;
  let inString = false;
  let escaped = false;

  for (let i = 0; i < s.length; i += 1) {
    const ch = s[i];

    if (inString) {
      if (escaped) escaped = false;
      else if (ch === '\\') escaped = true;
      else if (ch === '"') inString = false;
      continue;
    }

    if (ch === '"') {
      inString = true;
      continue;
    }

    if (ch === '{') {
      if (start === -1) start = i;
      depth += 1;
      continue;
    }

    if (ch === '}') {
      if (start !== -1) {
        depth -= 1;
        if (depth === 0) return s.slice(start, i + 1);
      }
    }
  }

  return null;
};

const removeTrailingCommas = (text) => text.replace(/,\s*([}\]])/g, '$1');
const clean = stripMarkdownFences(rawText);
const extracted = extractFirstJsonObject(clean);

const candidates = [];
const addCandidate = (v) => {
  if (typeof v !== 'string') return;
  const t = v.trim();
  if (t && !candidates.includes(t)) candidates.push(t);
};

addCandidate(clean);
addCandidate(extracted);
addCandidate(removeTrailingCommas(clean));
if (extracted) addCandidate(removeTrailingCommas(extracted));

let parsed = null;
let lastError = '';
for (const c of candidates) {
  try {
    parsed = JSON.parse(c);
    break;
  } catch (e) {
    lastError = String(e?.message || e);
  }
}

const normalizePriority = (value) => {
  const v = (value || '').toString().toLowerCase();
  if (v === 'high' || v === 'medium' || v === 'low') return v;
  return 'medium';
};

if (!parsed || typeof parsed !== 'object' || Array.isArray(parsed)) {
  if (doneReason === 'length') {
    const summaryMatch = clean.match(/"summary"\s*:\s*"([\s\S]{0,700}?)(?<!\\)"/);
    const partialSummary = summaryMatch
      ? summaryMatch[1]
      : 'Ответ модели был обрезан по лимиту токенов. Сократите входной текст или увеличьте лимиты генерации.';

    return [{
      json: {
        summary: partialSummary,
        tasks: [],
        departmentSuggestions: [],
        _meta: {
          truncated: true,
          doneReason,
          parseError: lastError,
          rawPreview: rawText.slice(0, 1000)
        }
      }
    }];
  }

  throw new Error(`Не удалось распарсить JSON от модели: ${lastError}. Превью ответа: ${rawText.slice(0, 1000)}`);
}

const summary = typeof parsed.summary === 'string'
  ? parsed.summary
  : 'Недостаточно данных для краткого описания';

const tasks = Array.isArray(parsed.tasks)
  ? parsed.tasks.map((t) => ({
      title: (t?.title || 'Без названия').toString(),
      description: (t?.description || 'Описание не предоставлено').toString(),
      priority: normalizePriority(t?.priority)
    }))
  : [];

const departmentSuggestions = Array.isArray(parsed.departmentSuggestions)
  ? parsed.departmentSuggestions.map((d) => ({
      departmentCode: (d?.departmentCode || '').toString(),
      relevanceReason: (d?.relevanceReason || 'Релевантность не указана').toString(),
      problemFragment: (d?.problemFragment || 'Фрагмент не указан').toString(),
      adaptedPitch: (d?.adaptedPitch || 'Пояснение не сформировано').toString(),
      emailSubject: (d?.emailSubject || 'Предложение по проекту').toString(),
      emailBody: (d?.emailBody || 'Текст письма не сформирован').toString()
    }))
  : [];

return [{
  json: {
    summary,
    tasks,
    departmentSuggestions,
    _meta: {
      truncated: false,
      doneReason,
      model: rawItem.model || null,
      promptEvalCount: rawItem.prompt_eval_count || null,
      evalCount: rawItem.eval_count || null
    }
  }
}];
